// Entrada: todos os itens (cada um com json contendo Nome, Email, Status)
const allItems = $input.all();

// Arrays para os dois outputs
const todos = [];
const candidatos = [];

for (let i = 0; i < allItems.length; i++) {
    const item = allItems[i];
    // Garantir campos
    item.json.Nome = item.json.Nome || "";
    item.json.Email = item.json.Email || "";
    item.json.Status = item.json.Status || "";
    // Adicionar índice
    item.json._index = i;

    // Clonar para evitar referência
    todos.push(item);

    // Verificar se Status está vazio (string vazia, null, undefined)
    const status = item.json.Status;
    if (status === "" || status == null || status === undefined) {
        // Candidato a envio
        candidatos.push(item);
    }
}

// Retornar dois outputs
return [
    todos,      // output 0
    candidatos  // output 1
];

const items = $input.all();
const now = new Date();
const dataHora = now.toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });

for (const item of items) {
    // Verifica se houve erro (propriedade 'error' pode estar presente)
    const erro = item.json.error;
    if (erro) {
        item.json.Status = `Erro: ${erro.message || erro}`;
    } else {
        item.json.Status = `Enviado em ${dataHora}`;
    }
}
return items;

// Este nó tem 2 inputs:
//   - Input 0: todos os originais (com _index)
//   - Input 1: itens processados (com _index e Status atualizado)

const inputs = $input.all();
const originais = inputs[0];  // array de itens do input 0
const processados = inputs[1]; // array de itens do input 1

// Criar mapa dos processados por _index
const mapa = new Map();
for (const p of processados) {
    mapa.set(p.json._index, p.json.Status);
}

// Atualizar os originais
const resultado = [];
for (const item of originais) {
    const idx = item.json._index;
    if (mapa.has(idx)) {
        item.json.Status = mapa.get(idx);
    }
    // Remover _index
    delete item.json._index;
    // Garantir campos (já garantidos)
    resultado.push(item);
}

return resultado;
